SELECT Name, Role, Salary, JoinDate, DeptID, ManagerID, Status
FROM Employees
WHERE Status = 'Active';

SELECT EmpID, Name, Status
FROM Employees
WHERE Status = 'Active';

SELECT ProjectName
FROM Projects
WHERE Status = 'In Progress';

SELECT COUNT(*) 
FROM Employees 
WHERE Status = 'Resigned';

SELECT EmpID, Name, JoinDate
FROM Employees
WHERE DATE(JoinDate) > '2023-01-01';

SELECT ProjectName 
FROM Projects 
WHERE EndDate IS NULL;

SELECT SkillName
FROM Skills
WHERE Category = 'Technical';

SELECT SUM(D.Budget) AS TotalBudget
FROM Projects P
LEFT JOIN Departments D ON P.DeptID = D.DeptID;

SELECT E.EmpID, E.Name, D.DeptName
FROM Employees E
INNER JOIN Departments D ON E.DeptID = D.DeptID;

SELECT Status, COUNT(DISTINCT ProjectID) AS ProjectCount
FROM Projects
GROUP BY Status;

SELECT ProjectID
FROM Projects
WHERE Status = 'Completed';

SELECT Name, Salary
FROM Employees
WHERE Salary > (
  SELECT AVG(Salary)
  FROM Employees
);
